```typescript
export type NotebookState =
  | { status: "none" }
  | { status: "draft"; id: string; owner: string; cells: number }
  | { status: "published"; id: string; publishedAt: string }
  | { status: "archived"; id: string; archivedAt: string };

export type NotebookCommand =
  | { type: "create"; id: string; owner: string }
  | { type: "appendCell" }
  | { type: "publish"; at: string }
  | { type: "archive"; at: string };

export type NotebookEvent =
  | { type: "NotebookCreated"; id: string; owner: string }
  | { type: "NotebookCellAppended" }
  | { type: "NotebookPublished"; at: string }
  | { type: "NotebookArchived"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const notebookDecider: Decider<NotebookCommand, NotebookEvent, NotebookState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "create":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "NotebookCreated", id: command.id, owner: command.owner }];
      case "appendCell":
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        return [{ type: "NotebookCellAppended" }];
      case "publish":
        if (state.status === "archived") throw new DomainError("ARCHIVED");
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        return [{ type: "NotebookPublished", at: command.at }];
      case "archive":
        if (state.status === "archived") throw new DomainError("ALREADY_ARCHIVED");
        return [{ type: "NotebookArchived", at: command.at }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "NotebookCreated":
        return { status: "draft", id: event.id, owner: event.owner, cells: 0 };
      case "NotebookCellAppended":
        if (state.status !== "draft") return state;
        return { ...state, cells: state.cells + 1 };
      case "NotebookPublished":
        if (state.status !== "draft") return state;
        return { status: "published", id: state.id, publishedAt: event.at };
      case "NotebookArchived":
        if (state.status === "archived" || state.status === "none") return state;
        return { status: "archived", id: "id" in state ? state.id : "", archivedAt: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
