  | { type: "create"; id: string; step: number }
  | { type: "attachArtifact"; uri: string }
  | { type: "promote"; stage: string }
  | { type: "retire" };

export type ModelCheckpointEvent =
  | { type: "CheckpointCreated"; id: string; step: number }
  | { type: "CheckpointArtifactAttached"; uri: string }
  | { type: "CheckpointPromoted"; stage: string }
  | { type: "CheckpointRetired" };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
