      case "retire":
        if (state.status === "retired" || state.status === "none") throw new DomainError("CANNOT_RETIRE");
        return [{ type: "CheckpointRetired" }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "CheckpointCreated":
        return { status: "created", id: event.id, step: event.step };
      case "CheckpointArtifactAttached":
        if (state.status !== "created") return state;
        return { status: "withArtifact", id: state.id, step: state.step, uri: event.uri };
      case "CheckpointPromoted":
        if (state.status !== "withArtifact") return state;
        return { status: "promoted", id: state.id, stage: event.stage };
      case "CheckpointRetired":
        if (state.status === "none") return state;
        return { status: "retired", id: "id" in state ? state.id : "" };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
