export type TrainingJobState =
  | { status: "none" }
  | { status: "queued"; id: string; image: string }
  | { status: "running"; id: string; epoch: number }
  | { status: "completed"; id: string; metric: number }
  | { status: "failed"; id: string; reason: string };

export type TrainingJobCommand =
  | { type: "submit"; id: string; image: string }
  | { type: "start" }
  | { type: "progress"; epoch: number }
  | { type: "complete"; metric: number }
  | { type: "fail"; reason: string };

export type TrainingJobEvent =
  | { type: "TrainingJobSubmitted"; id: string; image: string }
  | { type: "TrainingJobStarted" }
  | { type: "TrainingJobProgressed"; epoch: number }
  | { type: "TrainingJobCompleted"; metric: number }
  | { type: "TrainingJobFailed"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const trainingJobDecider: Decider<TrainingJobCommand, TrainingJobEvent, TrainingJobState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "submit":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "TrainingJobSubmitted", id: command.id, image: command.image }];
      case "start":
        if (state.status !== "queued") throw new DomainError("NOT_QUEUED");
        return [{ type: "TrainingJobStarted" }];
      case "progress":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "TrainingJobProgressed", epoch: command.epoch }];
      case "complete":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "TrainingJobCompleted", metric: command.metric }];
      case "fail":
        if (state.status !== "running" && state.status !== "queued") throw new DomainError("CANNOT_FAIL");
        return [{ type: "TrainingJobFailed", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "TrainingJobSubmitted":
        return { status: "queued", id: event.id, image: event.image };
      case "TrainingJobStarted":
        if (state.status !== "queued") return state;
        return { status: "running", id: state.id, epoch: 0 };
      case "TrainingJobProgressed":
        if (state.status !== "running") return state;
        return { ...state, epoch: event.epoch };
      case "TrainingJobCompleted":
        if (state.status !== "running") return state;
        return { status: "completed", id: state.id, metric: event.metric };
      case "TrainingJobFailed":
        if (state.status === "completed" || state.status === "failed" || state.status === "none") return state;
        return { status: "failed", id: state.id, reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
