    switch (event.type) {
      case "EvaluationQueued":
        return { status: "queued", id: event.id, modelId: event.modelId };
      case "EvaluationRan":
        if (state.status !== "queued") return state;
        return { status: "running", id: state.id };
      case "EvaluationPassed":
        if (state.status !== "running") return state;
        return { status: "passed", id: state.id, score: event.score };
      case "EvaluationFailed":
        if (state.status !== "running") return state;
        return { status: "failed", id: state.id, score: event.score, reason: event.reason };
