```typescript
export type GPUReservationState =
  | { status: "none" }
  | { status: "active"; id: string; from: number; to: number }
  | { status: "finished"; id: string }
  | { status: "cancelled"; id: string };

export type GPUReservationCommand =
  | { type: "reserve"; id: string; from: number; to: number }
  | { type: "finish" }
  | { type: "cancel" };

export type GPUReservationEvent =
  | { type: "GPUReserved"; id: string; from: number; to: number }
  | { type: "GPUReservationFinished" }
  | { type: "GPUReservationCancelled" };

export class InvariantError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "InvariantError";
  }
}

export function decide(command: GPUReservationCommand, state: GPUReservationState): GPUReservationEvent[] {
  switch (command.type) {
    case "reserve":
      if (state.status !== "none") throw new InvariantError("OVERLAP");
      if (command.to <= command.from) throw new InvariantError("BAD_WINDOW");
      return [{ type: "GPUReserved", id: command.id, from: command.from, to: command.to }];
    case "finish":
      if (state.status !== "active") throw new InvariantError("NOT_ACTIVE");
      return [{ type: "GPUReservationFinished" }];
    case "cancel":
      if (state.status === "finished") throw new InvariantError("ALREADY_FINISHED");
      if (state.status === "cancelled") throw new InvariantError("ALREADY_CANCELLED");
      if (state.status === "none") throw new InvariantError("NO_RESERVATION");
      return [{ type: "GPUReservationCancelled" }];
    default: {
      const _never: never = command;
      throw new InvariantError("UNKNOWN");
    }
  }
}
