export type TrainingJobEvent =
  | { type: "TrainingJobSubmitted"; day: string }
  | { type: "TrainingJobStarted"; day: string }
  | { type: "TrainingJobCompleted"; day: string }
  | { type: "TrainingJobFailed"; day: string };

export type DailyTally = { queued: number; running: number; completed: number; failed: number };
export type TrainingJobView = { byDay: Record<string, DailyTally> };

export const emptyView: TrainingJobView = { byDay: {} };

function bump(view: TrainingJobView, day: string, field: keyof DailyTally): TrainingJobView {
  const current: DailyTally = view.byDay[day] ?? { queued: 0, running: 0, completed: 0, failed: 0 };
  return { byDay: { ...view.byDay, [day]: { ...current, [field]: current[field] + 1 } } };
}

export function project(view: TrainingJobView, event: TrainingJobEvent): TrainingJobView {
  switch (event.type) {
    case "TrainingJobSubmitted":
      return bump(view, event.day, "queued");
    case "TrainingJobStarted":
      return bump(view, event.day, "running");
    case "TrainingJobCompleted":
      return bump(view, event.day, "completed");
    case "TrainingJobFailed":
      return bump(view, event.day, "failed");
    default: {
      const _never: never = event;
      return view;
    }
  }
}
