export type SweepEvent =
  | { type: "SweepPlanned"; id: string }
  | { type: "SweepStarted"; id: string }
  | { type: "SweepTrialRecorded"; id: string; score: number; trial: string }
  | { type: "SweepFinished"; id: string; bestScore: number };

export type SweepView = {
  id: string;
  running: boolean;
  bestTrial: string | null;
  bestScore: number;
  trials: number;
};

export const emptyView: SweepView = {
  id: "",
  running: false,
  bestTrial: null,
  bestScore: -Infinity,
  trials: 0,
};

export function project(view: SweepView, event: SweepEvent): SweepView {
  switch (event.type) {
    case "SweepPlanned":
      return view;
    case "SweepStarted":
      return { ...view, id: event.id, running: true };
    case "SweepTrialRecorded": {
      const trials = view.trials + 1;
      if (event.score > view.bestScore) {
        return { ...view, trials, bestTrial: event.trial, bestScore: event.score };
      }
      return { ...view, trials };
    }
    case "SweepFinished":
      return { ...view, running: false };
    default: {
      const _never: never = event;
      return view;
    }
  }
}
