```typescript
export type EvaluationEvent =
  | { type: "EvaluationPassed"; modelId: string; score: number }
  | { type: "EvaluationFailed"; modelId: string };

export type LeaderboardView = {
  leader: string | null;
  leaderScore: number;
  passes: Record<string, number>;
};

export const emptyView: LeaderboardView = {
  leader: null,
  leaderScore: -Infinity,
  passes: {},
};

export function project(view: LeaderboardView, event: EvaluationEvent): LeaderboardView {
  switch (event.type) {
    case "EvaluationPassed": {
      const passes = { ...view.passes, [event.modelId]: (view.passes[event.modelId] ?? 0) + 1 };
      if (event.score > view.leaderScore) {
        return { leader: event.modelId, leaderScore: event.score, passes };
      }
      return { ...view, passes };
    }
    case "EvaluationFailed":
      return view;
    default: {
