): Promise<S> {
  let state: S = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export type GPUReservationState =
  | { status: "none" }
  | { status: "active"; id: string; from: number; to: number }
  | { status: "finished"; id: string };

export type GPUReservationEvent =
  | { type: "GPUReserved"; id: string; from: number; to: number }
  | { type: "GPUReservationFinished" };

const empty: GPUReservationState = { status: "none" };

export function when(state: GPUReservationState, event: GPUReservationEvent): GPUReservationState {
  switch (event.type) {
    case "GPUReserved":
      return { status: "active", id: event.id, from: event.from, to: event.to };
    case "GPUReservationFinished":
      return state.status === "active" ? { status: "finished", id: state.id } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export const loadReservation = (stream: AsyncIterable<GPUReservationEvent>) =>
  Effect.promise(() => aggregateStream(stream, when, empty));
