export type FeatureStoreEvent =
  | { type: "FeatureStoreCreated"; id: string }
  | { type: "FeatureAdded"; name: string }
  | { type: "FeatureStoreSealed" };

export type FeatureStoreView = { id: string; features: string[]; sealed: boolean };
const empty: FeatureStoreView = { id: "", features: [], sealed: false };

function project(view: FeatureStoreView, event: FeatureStoreEvent): FeatureStoreView {
  switch (event.type) {
