import { Effect } from "effect";

export type EvaluationEvent =
  | { type: "EvaluationPassed"; score: number }
  | { type: "EvaluationFailed"; reason: string };

export interface EventStore {
  appendToStream<E>(stream: string, events: E[], options: { expectedRevision: bigint | "no_stream" | "any" }): Promise<{ ok: true; revision: bigint } | { ok: false }>;
}

export class ConcurrencyConflict extends Error {
  readonly _tag = "ConcurrencyConflict";
  constructor(public readonly stream: string) {
    super(`conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export const appendEvaluation = (
  store: EventStore,
  stream: string,
  expectedRevision: bigint | "no_stream" | "any",
  events: EvaluationEvent[],
) =>
  Effect.gen(function* () {
    const result = yield* Effect.promise(() => store.appendToStream(stream, events, { expectedRevision }));
    if (!result.ok) {
      yield* Effect.fail(new ConcurrencyConflict(stream));
      return 0n;
    }
    return result.revision;
  });
