export type TrainingJobState =
  | { status: "queued"; id: string }
  | { status: "running"; id: string; epoch: number }
  | { status: "completed"; id: string };

export type TrainingJobCommand =
  | { type: "progress"; epoch: number }
  | { type: "complete"; metric: number };

export type TrainingJobEvent =
  | { type: "TrainingJobProgressed"; epoch: number }
  | { type: "TrainingJobCompleted"; metric: number };

export class InvariantError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "InvariantError";
  }
}

export function decide(command: TrainingJobCommand, state: TrainingJobState): TrainingJobEvent[] {
  switch (command.type) {
    case "progress":
      if (state.status !== "running") throw new InvariantError("NOT_RUNNING");
      if (command.epoch <= state.epoch) throw new InvariantError("NON_MONOTONIC");
      return [{ type: "TrainingJobProgressed", epoch: command.epoch }];
    case "complete":
      if (state.status !== "running") throw new InvariantError("NOT_RUNNING");
      if (state.epoch < 3) throw new InvariantError("TOO_EARLY");
      return [{ type: "TrainingJobCompleted", metric: command.metric }];
    default: {
      const _never: never = command;
      throw new InvariantError("UNKNOWN");
    }
  }
}
